import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { TextField, FormGroup, FormControl, FormLabel, Typography, Button } from '@material-ui/core';
import { appActions, alertAction } from '../../../actions';
import { trackerUtil, trackerActions, onEnterPress, socketSetup } from '../utils';
import { routeNamesTracker } from '../routeNames';
import { socketIOStrings } from '../../../socket.io';


const style = theme => ({
    root: {
        background : "url('./images/background_map.jpg') no-repeat center center",
        backgroundSize : "cover",
        height : "100vh",
        width : "100vw",
    },
    overLay : {
        height : "100%",
        width : "100%",
        backgroundColor : trackerUtil.getTheme().primaryTrans,
        display : "flex",
        alignItems : "center",
        justifyContent : "center"
    },
    formContainer : {
        backgroundColor : trackerUtil.getTheme().primary, 
        padding : 20,
        borderRadius : 10,
        width : "50%",
        [theme.breakpoints.down("xs")] : {
            width : "80%"
        },
        [theme.breakpoints.up("md")] : {
            width : "30%",
        }
    },
    textField : {
        background : trackerUtil.getTheme().white,
        borderRadius : 5,
        border : "none"
    },
    noBorder : {
        border : "none"
    },
    headerContainer : {
        marginBottom : 50,
    },
    header : {
        color : trackerUtil.getTheme().white,
        fontWeight : "bold"
    },
    loginButton : {
        marginTop : 20,
        backgroundColor : trackerUtil.getTheme().primary,
        color : trackerUtil.getTheme().white
    }
})
class _Login extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data  : {
                email : "",
                password : "",
                loading : false
            },
            loading : false
        }
    }
    handleChange=name=>event=>{
        let value = event.target.value;
        let data = {...this.state.data};
        data[name] = value;
        this.setState({data});
    }
    login(){
        this.setState({loading : true});
        const {email, password} = this.state.data;
        const {dispatch, [socketIOStrings.socket] : socket} = this.props;
        if(email.trim() === "" && password.trim() === ""){
            appActions.showSnackbar(
                alertAction.error("Empty field error!")
            )(this.props.dispatch);
            this.setState({loading : false});
            return;
        }
        trackerActions.loging(email, password, done => {
            this.setState({loading : false});
            if(done){
                socket.disconnect();
                socketSetup(()=>{
                    this.props.history.replace(routeNamesTracker.dashboard);
                });
            }
        })(dispatch);
    }
    render() {
        const {classes} = this.props;
        const {username, password, loading} = this.state;
        return (
            <div id="home" className={classes.root}>
                <div className={classes.overLay}>
                    <div className={classes.formContainer}>
                        <FormGroup>
                            <FormLabel className={classes.headerContainer}>
                                <Typography className={classes.header} component="h4" variant="h4">Login</Typography>
                            </FormLabel>
                            <FormControl>
                                <TextField
                                    label="Email"
                                    placeholder="email"
                                    margin="normal"
                                    onChange={this.handleChange("email")}
                                    value={username}
                                    className={classes.textField}
                                    variant="outlined"
                                    onKeyDown={onEnterPress(this.login.bind(this))}/>
                            </FormControl>
                            <FormControl>
                                <TextField
                                    label="Password"
                                    placeholder="password"
                                    margin="normal"
                                    onChange={this.handleChange("password")}
                                    value={password}
                                    type="password"
                                    className={classes.textField}
                                    variant="outlined"
                                    onKeyDown={onEnterPress(this.login.bind(this))}/>
                            </FormControl>
                            <FormControl>
                                <Button
                                    disabled={loading}
                                    className={classes.loginButton}
                                    onClick={()=>this.login()}>
                                        Login
                                    </Button>
                            </FormControl>
                            <div style={{marginTop : 20, direction : "rtl"}}>
                                <Button
                                    className={classes.loginButton}
                                    variant="text"
                                    onClick={()=>this.props.history.replace(routeNamesTracker.signup)}>
                                        Sign up
                                    </Button>
                            </div>
                        </FormGroup>
                    </div>
                </div>
            
            </div>
        );
    }
}


_Login.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({socketIOReducer}) => ({
    [socketIOStrings.socket] : socketIOReducer[socketIOStrings.socket],
})


export const Login = connect(mapStateToProps)(withStyles(style)(_Login));
export {Login as default};